import React, { useState } from 'react';
import FormInput from '../components/FormInput';
import Button from '../components/Button';
import Card from '../components/Card';
import { serviceAPI, apiUtils } from '../services/api';

const EstimatePrice = () => {
  const [formData, setFormData] = useState({
    bikeModel: '',
    serviceType: '',
    doorstepService: false,
    urgentService: false
  });
  const [estimate, setEstimate] = useState(null);
  const [loading, setLoading] = useState(false);

  const bikeModels = [
    { value: 'honda-cb-shine', label: 'Honda CB Shine', category: 'commuter' },
    { value: 'hero-splendor', label: 'Hero Splendor Plus', category: 'commuter' },
    { value: 'bajaj-pulsar-150', label: 'Bajaj Pulsar 150', category: 'sports' },
    { value: 'tvs-apache', label: 'TVS Apache RTR 160', category: 'sports' },
    { value: 'yamaha-fz', label: 'Yamaha FZ-S', category: 'sports' },
    { value: 're-classic', label: 'Royal Enfield Classic 350', category: 'cruiser' },
    { value: 'ktm-duke', label: 'KTM Duke 200', category: 'sports' },
    { value: 'suzuki-gixxer', label: 'Suzuki Gixxer', category: 'sports' }
  ];

  const serviceTypes = [
    { value: 'basic', label: 'Basic Service', basePrice: 500 },
    { value: 'standard', label: 'Standard Service', basePrice: 800 },
    { value: 'premium', label: 'Premium Service', basePrice: 1200 },
    { value: 'oil-change', label: 'Oil Change', basePrice: 300 },
    { value: 'brake-service', label: 'Brake Service', basePrice: 600 },
    { value: 'chain-cleaning', label: 'Chain Cleaning & Lubrication', basePrice: 200 },
    { value: 'tire-replacement', label: 'Tire Replacement', basePrice: 1500 },
    { value: 'engine-tuning', label: 'Engine Tuning', basePrice: 2000 },
    { value: 'electrical-check', label: 'Electrical System Check', basePrice: 400 },
    { value: 'carburetor-cleaning', label: 'Carburetor Cleaning', basePrice: 700 }
  ];

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  };

  const calculateEstimate = () => {
    setLoading(true);

    setTimeout(() => {
      const selectedBike = bikeModels.find(bike => bike.value === formData.bikeModel);
      const selectedService = serviceTypes.find(service => service.value === formData.serviceType);

      if (!selectedBike || !selectedService) {
        setLoading(false);
        return;
      }

      let basePrice = selectedService.basePrice;

      // Category multiplier
      const categoryMultiplier = {
        'commuter': 1.0,
        'sports': 1.2,
        'cruiser': 1.3
      };

      basePrice *= categoryMultiplier[selectedBike.category] || 1.0;

      // Additional charges
      const doorstepCharge = formData.doorstepService ? 100 : 0;
      const urgentCharge = formData.urgentService ? 200 : 0;

      const subtotal = basePrice + doorstepCharge + urgentCharge;
      const tax = subtotal * 0.18; // 18% GST
      const total = subtotal + tax;

      setEstimate({
        bikeModel: selectedBike.label,
        serviceType: selectedService.label,
        basePrice: Math.round(basePrice),
        doorstepCharge,
        urgentCharge,
        subtotal: Math.round(subtotal),
        tax: Math.round(tax),
        total: Math.round(total),
        estimatedTime: getEstimatedTime(formData.serviceType),
        warranty: getWarranty(formData.serviceType)
      });

      setLoading(false);
    }, 1000);
  };

  const getEstimatedTime = (serviceType) => {
    const timeMap = {
      'basic': '2-3 hours',
      'standard': '3-4 hours',
      'premium': '4-6 hours',
      'oil-change': '30 minutes',
      'brake-service': '1-2 hours',
      'chain-cleaning': '30 minutes',
      'tire-replacement': '1 hour',
      'engine-tuning': '4-6 hours',
      'electrical-check': '1-2 hours',
      'carburetor-cleaning': '2-3 hours'
    };
    return timeMap[serviceType] || '2-4 hours';
  };

  const getWarranty = (serviceType) => {
    const warrantyMap = {
      'basic': '15 days',
      'standard': '30 days',
      'premium': '45 days',
      'oil-change': '15 days',
      'brake-service': '30 days',
      'chain-cleaning': '15 days',
      'tire-replacement': '90 days',
      'engine-tuning': '60 days',
      'electrical-check': '30 days',
      'carburetor-cleaning': '30 days'
    };
    return warrantyMap[serviceType] || '30 days';
  };

  return (
    <div className="estimate-price">
      <div className="container">
        <div className="page-header">
          <h1>Estimate Price</h1>
          <p>Get instant price estimates for bike services and repairs</p>
        </div>

        <div className="estimate-content">
          <div className="estimate-form-section">
            <Card className="estimate-form-card">
              <h2>Service Details</h2>
              <form className="estimate-form">
                <FormInput
                  label="Bike Model"
                  type="select"
                  name="bikeModel"
                  value={formData.bikeModel}
                  onChange={handleChange}
                  options={bikeModels}
                  placeholder="Select your bike model"
                  required
                />

                <FormInput
                  label="Service Type"
                  type="select"
                  name="serviceType"
                  value={formData.serviceType}
                  onChange={handleChange}
                  options={serviceTypes}
                  placeholder="Select service type"
                  required
                />

                <div className="checkbox-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="doorstepService"
                      checked={formData.doorstepService}
                      onChange={handleChange}
                    />
                    <span className="checkmark"></span>
                    Doorstep Service (+₹100)
                  </label>
                </div>

                <div className="checkbox-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="urgentService"
                      checked={formData.urgentService}
                      onChange={handleChange}
                    />
                    <span className="checkmark"></span>
                    Urgent Service (+₹200)
                  </label>
                </div>

                <Button
                  type="button"
                  variant="primary"
                  size="large"
                  onClick={calculateEstimate}
                  disabled={!formData.bikeModel || !formData.serviceType || loading}
                  className="estimate-btn"
                >
                  {loading ? 'Calculating...' : 'Get Price Estimate'}
                </Button>
              </form>
            </Card>
          </div>

          <div className="estimate-result-section">
            {estimate ? (
              <Card className="estimate-result-card">
                <h2>Price Estimate</h2>
                <div className="estimate-details">
                  <div className="estimate-header">
                    <h3>{estimate.bikeModel}</h3>
                    <p>{estimate.serviceType}</p>
                  </div>

                  <div className="estimate-breakdown">
                    <div className="breakdown-item">
                      <span>Base Service Price</span>
                      <span>₹{estimate.basePrice}</span>
                    </div>
                    {estimate.doorstepCharge > 0 && (
                      <div className="breakdown-item">
                        <span>Doorstep Service</span>
                        <span>₹{estimate.doorstepCharge}</span>
                      </div>
                    )}
                    {estimate.urgentCharge > 0 && (
                      <div className="breakdown-item">
                        <span>Urgent Service</span>
                        <span>₹{estimate.urgentCharge}</span>
                      </div>
                    )}
                    <div className="breakdown-item subtotal">
                      <span>Subtotal</span>
                      <span>₹{estimate.subtotal}</span>
                    </div>
                    <div className="breakdown-item">
                      <span>GST (18%)</span>
                      <span>₹{estimate.tax}</span>
                    </div>
                    <div className="breakdown-item total">
                      <span>Total Amount</span>
                      <span>₹{estimate.total}</span>
                    </div>
                  </div>

                  <div className="estimate-info">
                    <div className="info-item">
                      <span className="info-icon">⏱️</span>
                      <div>
                        <strong>Estimated Time</strong>
                        <p>{estimate.estimatedTime}</p>
                      </div>
                    </div>
                    <div className="info-item">
                      <span className="info-icon">🛡️</span>
                      <div>
                        <strong>Warranty</strong>
                        <p>{estimate.warranty}</p>
                      </div>
                    </div>
                  </div>

                  <Button variant="primary" size="large" className="book-now-btn">
                    Book This Service
                  </Button>
                </div>
              </Card>
            ) : (
              <Card className="estimate-placeholder">
                <div className="placeholder-content">
                  <div className="placeholder-icon">💰</div>
                  <h3>Price Estimate</h3>
                  <p>Select your bike model and service type to get an instant price estimate</p>
                </div>
              </Card>
            )}
          </div>
        </div>

        {/* Popular Services */}
        <section className="popular-services">
          <h2>Popular Services</h2>
          <div className="popular-grid">
            <Card className="popular-card">
              <h3>Basic Service</h3>
              <div className="popular-price">Starting from ₹500</div>
              <p>Essential maintenance for your bike</p>
            </Card>
            <Card className="popular-card">
              <h3>Oil Change</h3>
              <div className="popular-price">Starting from ₹300</div>
              <p>Fresh engine oil for smooth performance</p>
            </Card>
            <Card className="popular-card">
              <h3>Premium Service</h3>
              <div className="popular-price">Starting from ₹1200</div>
              <p>Complete bike service and inspection</p>
            </Card>
          </div>
        </section>
      </div>
    </div>
  );
};

export default EstimatePrice;
